    /**
     * @return array<string, mixed>
     */
    private static function def(
        string $slug,
        string $title,
        string $category,
        string $excerpt,
        string $metaTitle,
        string $metaDescription,
        string $metaKeywords,
    ): array {
        return [
            'slug' => $slug,
            'title' => $title,
            'category' => $category,
            'excerpt' => $excerpt,
            'meta_title' => $metaTitle,
            'meta_description' => $metaDescription,
            'meta_keywords' => $metaKeywords,
        ];
    }

    public static function build(array $definition): string
    {
        $focus = self::focusFor($definition['category']);
        $html = self::article($focus['keyword'], $focus['intro'], $focus['sections']);

        return $html.self::enrich($definition['title'], $focus['keyword'], $definition['category']);
    }

