                    ['heading' => 'Cross-Referencing Records', 'paragraphs' => ['Names, survey numbers, and areas must match across deed, EC, tax records, and society files. Any variance needs documented correction before purchase.']],
                ],
            ],
            'first_time_legal' => [
                'keyword' => 'real estate legal checklist for first-time home buyers',
                'intro' => 'First-time buyers benefit from ordered milestones — loan pre-approval, RERA check, site visit, advocate review, agreement, registration — without skipping legal steps for emotional urgency.',
                'sections' => [
                    ['heading' => 'First-Timer Legal Milestones', 'paragraphs' => ['Budget stamp duty and registration upfront. Never sign builder agreements without advocate review. Keep 7–10 days for legal diligence before token.'], 'list' => ['Loan pre-approval and budget', 'RERA / title preliminary check', 'Advocate engagement before token', 'Agreement review', 'Registration prep']],
                ],
            ],
            'plot_docs' => [
                'keyword' => 'documents to verify before buying a plot',
                'intro' => 'Plot verification emphasises land title, conversion status, layout approval, and boundaries — build plans come later but land legality comes first.',
                'sections' => [
                    ['heading' => 'Plot Verification List', 'paragraphs' => ['Reject plots with unclear conversion or disputed boundaries — the cheapest plot often carries the highest legal risk.'], 'list' => ['Title deed and 13–30 year chain', 'Conversion / CLU order', 'Layout plan sanction', 'EC without mortgage surprises', 'Physical boundary verification']],
                ],
            ],
            default => [
                'keyword' => 'property document verification in India',
                'intro' => 'Property document verification protects buyers from title defects, hidden liabilities, and registration failures.',
